  1→/**
  2→ * sequant_logs MCP tool
  3→ *
  4→ * Get run logs and metrics.
  5→ */
  6→
  7→import { z } from "zod";
  8→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  9→import * as fs from "fs";
 10→import * as path from "path";
 11→import * as os from "os";
 12→import { LOG_PATHS, RunLogSchema } from "../../lib/workflow/run-log-schema.js";
 13→import type { RunLog } from "../../lib/workflow/run-log-schema.js";
 14→
 15→function resolveLogPath(): string {
 16→  const projectPath = LOG_PATHS.project;
 17→  if (fs.existsSync(projectPath)) {
 18→    return projectPath;
 19→  }
 20→
 21→  const userPath = LOG_PATHS.user.replace("~", os.homedir());
 22→  if (fs.existsSync(userPath)) {
 23→    return userPath;
 24→  }
 25→
 26→  return projectPath;
 27→}
 28→
 29→function parseLogFile(filePath: string): RunLog | null {
 30→  try {
 31→    const content = fs.readFileSync(filePath, "utf-8");
 32→    const data = JSON.parse(content);
 33→    return RunLogSchema.parse(data);
 34→  } catch {
 35→    return null;
 36→  }
 37→}
 38→
 39→export function registerLogsTool(server: McpServer): void {
 40→  server.registerTool(
 41→    "sequant_logs",
 42→    {
 43→      title: "Sequant Logs",
 44→      description: "Get structured run logs for recent workflow executions",
 45→      inputSchema: {
 46→        runId: z
 47→          .string()
 48→          .optional()
 49→          .describe("Specific run ID (optional, defaults to latest)"),
 50→        limit: z
 51→          .number()
 52→          .optional()
 53→          .describe("Number of recent runs to return (default: 5)"),
 54→      },
 55→    },
 56→    async ({ runId, limit }) => {
 57→      try {
 58→        const logDir = resolveLogPath();
 59→
 60→        if (!fs.existsSync(logDir)) {
 61→          return {
 62→            content: [
 63→              {
 64→                type: "text" as const,
 65→                text: JSON.stringify({
 66→                  logs: [],
 67→                  message:
 68→                    "No log directory found. Run `sequant run` to generate logs.",
 69→                }),
 70→              },
 71→            ],
 72→          };
 73→        }
 74→
 75→        const logFiles = fs
 76→          .readdirSync(logDir)
 77→          .filter((f) => f.startsWith("run-") && f.endsWith(".json"))
 78→          .sort()
 79→          .reverse();
 80→
 81→        if (logFiles.length === 0) {
 82→          return {
 83→            content: [
 84→              {
 85→                type: "text" as const,
 86→                text: JSON.stringify({
 87→                  logs: [],
 88→                  message: "No logs found.",
 89→                }),
 90→              },
 91→            ],
 92→          };
 93→        }
 94→
 95→        let logs: RunLog[] = [];
 96→        for (const filename of logFiles) {
 97→          const filePath = path.join(logDir, filename);
 98→          const log = parseLogFile(filePath);
 99→          if (log) {
100→            // Filter by runId if specified
101→            if (runId && !log.runId.startsWith(runId)) {
102→              continue;
103→            }
104→            logs.push(log);
105→          }
106→        }
107→
108→        // Apply limit
109→        const maxResults = limit && limit > 0 ? limit : 5;
110→        logs = logs.slice(0, maxResults);
111→
112→        return {
113→          content: [
114→            {
115→              type: "text" as const,
116→              text: JSON.stringify({
117→                count: logs.length,
118→                logs: logs.map((log) => ({
119→                  runId: log.runId,
120→                  startTime: log.startTime,
121→                  config: log.config,
122→                  summary: log.summary,
123→                  issues: log.issues.map((issue) => ({
124→                    issueNumber: issue.issueNumber,
125→                    title: issue.title,
126→                    status: issue.status,
127→                    totalDurationSeconds: issue.totalDurationSeconds,
128→                    phases: issue.phases.map((p) => ({
129→                      phase: p.phase,
130→                      status: p.status,
131→                      durationSeconds: p.durationSeconds,
132→                      error: p.error,
133→                    })),
134→                  })),
135→                })),
136→              }),
137→            },
138→          ],
139→        };
140→      } catch (error) {
141→        return {
142→          content: [
143→            {
144→              type: "text" as const,
145→              text: JSON.stringify({
146→                error: "LOGS_ERROR",
147→                message: error instanceof Error ? error.message : String(error),
148→              }),
149→            },
150→          ],
151→          isError: true,
152→        };
153→      }
154→    },
155→  );
156→}
