 13→import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
 14→import { Client } from "@modelcontextprotocol/sdk/client/index.js";
 15→import { InMemoryTransport } from "@modelcontextprotocol/sdk/inMemory.js";
 16→
 17→// Mock child_process before importing server (which imports tools/run.ts)
 18→vi.mock("child_process", async (importOriginal) => {
 19→  const actual = await importOriginal<typeof import("child_process")>();
 20→  return {
 21→    ...actual,
 22→    spawnSync: vi.fn(),
 23→  };
 24→});
