 26→import { createServer } from "./server.js";
 27→import { spawnSync } from "child_process";
 28→
 29→const mockedSpawnSync = vi.mocked(spawnSync);
 30→
 31→describe("Sequant MCP Server — Extended", () => {
 32→  let client: Client;
 33→  let cleanup: () => Promise<void>;
 34→
 35→  beforeEach(async () => {
 36→    vi.clearAllMocks();
 37→
 38→    const server = createServer("1.0.0-test");
 39→    const clientInstance = new Client({
 40→      name: "test-client",
 41→      version: "1.0.0",
 42→    });
