 60→  });
 61→
 62→  // AC-2: sequant_run tool — execution behavior
 63→  describe("AC-2: sequant_run execution", () => {
 64→    it("should accept valid issues array and return structured result", async () => {
 65→      mockedSpawnSync.mockReturnValue({
 66→        status: 0,
 67→        stdout: '{"summary":"completed"}',
 68→        stderr: "",
 69→        pid: 1234,
 70→        output: ["", '{"summary":"completed"}', ""],
 71→        signal: null,
 72→        error: undefined,
 73→      });
 74→
 75→      const result = await client.callTool({
 76→        name: "sequant_run",
 77→        arguments: { issues: [100] },
 78→      });
 79→
 80→      expect(result.isError).toBeFalsy();
 81→      const data = JSON.parse(
 82→        (result.content as Array<{ type: string; text: string }>)[0].text,
 83→      );
 84→      expect(data.status).toBe("success");
 85→      expect(data.issues).toEqual([100]);
 86→      expect(data.phases).toBeDefined();
 87→      expect(data.output).toBeDefined();
 88→    });
