 95→          arguments: { issues: [] },
 96→        });
 97→
 98→        expect(result.isError).toBe(true);
 99→        const data = JSON.parse(
100→          (result.content as Array<{ type: string; text: string }>)[0].text,
101→        );
102→        expect(data.error).toBe("INVALID_INPUT");
103→      });
104→
105→      it("should return isError when subprocess fails", async () => {
106→        mockedSpawnSync.mockReturnValue({
107→          status: 1,
108→          stdout: "partial output",
109→          stderr: "Error: something went wrong",
110→          pid: 1234,
111→          output: ["", "partial output", "Error: something went wrong"],
112→          signal: null,
113→          error: undefined,
114→        });
115→
116→        const result = await client.callTool({
117→          name: "sequant_run",
118→          arguments: { issues: [200] },
119→        });
120→
121→        expect(result.isError).toBe(true);
122→        const data = JSON.parse(
123→          (result.content as Array<{ type: string; text: string }>)[0].text,
124→        );
125→        expect(data.status).toBe("failure");
126→        expect(data.exitCode).toBe(1);
127→        expect(data.error).toContain("something went wrong");
