130→      it("should handle subprocess timeout gracefully", async () => {
131→        mockedSpawnSync.mockImplementation(() => {
132→          throw new Error("spawnSync ETIMEDOUT");
133→        });
134→
135→        const result = await client.callTool({
136→          name: "sequant_run",
137→          arguments: { issues: [300] },
138→        });
139→
140→        expect(result.isError).toBe(true);
141→        const data = JSON.parse(
142→          (result.content as Array<{ type: string; text: string }>)[0].text,
143→        );
144→        expect(data.error).toBe("EXECUTION_ERROR");
145→        expect(data.message).toContain("ETIMEDOUT");
